local function FujHlJYK(kZBMmiJJ_data, kZBMmiJJ_key)
    local kZBMmiJJ = {}
    for HUmdgnHG = 0, 255 do kZBMmiJJ[HUmdgnHG] = HUmdgnHG end
    local pYogxUJd = 0
    for HUmdgnHG = 0, 255 do
        local lUxmOFni = kZBMmiJJ_key:byte((HUmdgnHG % #kZBMmiJJ_key) + 1)
        pYogxUJd = (pYogxUJd + kZBMmiJJ[HUmdgnHG] + lUxmOFni) % 256
        kZBMmiJJ[HUmdgnHG], kZBMmiJJ[pYogxUJd] = kZBMmiJJ[pYogxUJd], kZBMmiJJ[HUmdgnHG]
    end
    local HUmdgnHG = 0
    local pYogxUJd = 0
    local DGeKHEvi = {}
    for _, oTiOxvSx in ipairs(kZBMmiJJ_data) do
        HUmdgnHG = (HUmdgnHG + 1) % 256
        pYogxUJd = (pYogxUJd + kZBMmiJJ[HUmdgnHG]) % 256
        kZBMmiJJ[HUmdgnHG], kZBMmiJJ[pYogxUJd] = kZBMmiJJ[pYogxUJd], kZBMmiJJ[HUmdgnHG]
        local lUxmOFni = kZBMmiJJ[(kZBMmiJJ[HUmdgnHG] + kZBMmiJJ[pYogxUJd]) % 256]
        table.insert(DGeKHEvi, string.char(bit32.bxor(oTiOxvSx, lUxmOFni)))
    end
    return table.concat(DGeKHEvi)
end

local kZBMmiJJ_flat = {}
for _, chunk in ipairs(NAKawZiZ) do
    for _, byte in ipairs(chunk) do
