    end
end

return function(cDYtQPmq, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = FujHlJYK(kZBMmiJJ_flat, cDYtQPmq)
    local qklwlYtp, MAJXPJqQ = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(kZBMmiJJ_flat)
    kZBMmiJJ_flat = nil
    
    if qklwlYtp then 
        local result = qklwlYtp(cDYtQPmq, ...) 
        decrypted = nil
        qklwlYtp = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "sell_lemons" .. "): " .. tostring(MAJXPJqQ)) 
    end
end
